import React, { createContext, useContext, useReducer, useEffect } from 'react';
import { useQuery, useQueryClient } from 'react-query';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import api from '../services/api';

const AuthContext = createContext();

const initialState = {
  user: null,
  token: localStorage.getItem('token'),
  isAuthenticated: false,
  isLoading: true,
};

const authReducer = (state, action) => {
  switch (action.type) {
    case 'LOGIN_START':
      return {
        ...state,
        isLoading: true,
      };
    case 'LOGIN_SUCCESS':
      return {
        ...state,
        user: action.payload.user,
        token: action.payload.token,
        isAuthenticated: true,
        isLoading: false,
      };
    case 'LOGIN_FAILURE':
      return {
        ...state,
        user: null,
        token: null,
        isAuthenticated: false,
        isLoading: false,
      };
    case 'LOGOUT':
      return {
        ...state,
        user: null,
        token: null,
        isAuthenticated: false,
        isLoading: false,
      };
    case 'UPDATE_USER':
      return {
        ...state,
        user: action.payload,
      };
    default:
      return state;
  }
};

export const AuthProvider = ({ children }) => {
  const [state, dispatch] = useReducer(authReducer, initialState);
  const queryClient = useQueryClient();
  const navigate = useNavigate();

  // Fetch user data if token exists
  const { data: userData, isLoading: userLoading } = useQuery(
    ['user', state.token],
    () => api.get('/api/profile/'),
    {
      enabled: !!state.token,
      retry: false,
      onSuccess: (data) => {
        dispatch({ type: 'UPDATE_USER', payload: data });
      },
      onError: () => {
        dispatch({ type: 'LOGIN_FAILURE' });
        localStorage.removeItem('token');
      },
    }
  );

  useEffect(() => {
    if (state.token && userData) {
      dispatch({ type: 'LOGIN_SUCCESS', payload: { user: userData, token: state.token } });
    } else if (!state.token) {
      dispatch({ type: 'LOGIN_FAILURE' });
    }
  }, [state.token, userData]);

  const login = async (credentials) => {
    try {
      dispatch({ type: 'LOGIN_START' });

      const response = await api.post('/api/login/', credentials);
      const { user, access, refresh } = response.data;

      localStorage.setItem('token', access);
      localStorage.setItem('refreshToken', refresh);

      dispatch({ type: 'LOGIN_SUCCESS', payload: { user, token: access } });

      toast.success('Login successful!');
      navigate('/dashboard');

      return { success: true };
    } catch (error) {
      dispatch({ type: 'LOGIN_FAILURE' });

      const message = error.response?.data?.error || 'Login failed. Please try again.';
      toast.error(message);

      return { success: false, error: message };
    }
  };

  const register = async (userData) => {
    try {
      const response = await api.post('/api/register/', userData);
      const { user, access, refresh } = response.data;

      localStorage.setItem('token', access);
      localStorage.setItem('refreshToken', refresh);

      dispatch({ type: 'LOGIN_SUCCESS', payload: { user, token: access } });

      toast.success('Registration successful! Welcome to EroStream!');
      navigate('/dashboard');

      return { success: true };
    } catch (error) {
      const message = error.response?.data?.error || 'Registration failed. Please try again.';
      toast.error(message);

      return { success: false, error: message };
    }
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('refreshToken');

    dispatch({ type: 'LOGOUT' });
    queryClient.clear();

    toast.success('Logged out successfully');
    navigate('/');
  };

  const updateUser = (userData) => {
    dispatch({ type: 'UPDATE_USER', payload: userData });
  };

  const refreshToken = async () => {
    try {
      const refresh = localStorage.getItem('refreshToken');
      if (!refresh) throw new Error('No refresh token');

      const response = await api.post('/api/token/refresh/', { refresh });
      const { access } = response.data;

      localStorage.setItem('token', access);

      return access;
    } catch (error) {
      logout();
      throw error;
    }
  };

  const value = {
    ...state,
    login,
    register,
    logout,
    updateUser,
    refreshToken,
    isLoading: state.isLoading || userLoading,
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
